app = func.FunctionApp()

logger = logging.getLogger("azure.function")
logger.setLevel(logging.INFO)

credential = DefaultAzureCredential()

BLOB_ACCOUNT_URL = os.environ.get("BLOB_ACCOUNT_URL", "")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "mvpdb")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "files")
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT", "")
EVENT_GRID_TOPIC_KEY = os.environ.get("EVENT_GRID_TOPIC_KEY", "")

COSMOS_PARTITION_KEY_PATH = os.environ.get("COSMOS_PARTITION_KEY_PATH", "/id")


def _get_blob_client(container_name: str, blob_name: str) -> BlobClient:
    if not BLOB_ACCOUNT_URL:
        raise ValueError("BLOB_ACCOUNT_URL is required")
    return BlobClient(
        account_url=BLOB_ACCOUNT_URL,
        container_name=container_name,
        blob_name=blob_name,
        credential=credential,
    )


def _get_cosmos_container():
    if not COSMOS_ENDPOINT:
        raise ValueError("COSMOS_ENDPOINT is required")
    client = CosmosClient(COSMOS_ENDPOINT, credential=credential)
    database = client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key={"paths": [COSMOS_PARTITION_KEY_PATH], "kind": "Hash"},
        offer_throughput=400,
    )
    return container


def _send_event(event_type: str, subject: str, data: dict):
    if not EVENT_GRID_TOPIC_ENDPOINT:
        logger.warning("EVENT_GRID_TOPIC_ENDPOINT not configured; skipping event send")
        return

    event = EventGridEvent(
        subject=subject,
        data=data,
        event_type=event_type,
        data_version="1.0",
    )

    if EVENT_GRID_TOPIC_KEY:
        client = EventGridPublisherClient(
            endpoint=EVENT_GRID_TOPIC_ENDPOINT,
            credential=AzureKeyCredential(EVENT_GRID_TOPIC_KEY),
        )
    else:
        client = EventGridPublisherClient(
            endpoint=EVENT_GRID_TOPIC_ENDPOINT,
            credential=credential,
        )

    with client:
        client.send([event])


def _process_blob_content(content: bytes, blob_name: str) -> dict:
    text = content.decode("utf-8", errors="replace")
    lines = text.splitlines()
    word_count = len(text.split())
    return {
        "blobName": blob_name,
        "byteLength": len(content),
        "lineCount": len(lines),
        "wordCount": word_count,
        "preview": text[:500],
        "processedAt": datetime.now(timezone.utc).isoformat(),
    }


@app.function_name(name="ProcessBlob")
@app.blob_trigger(arg_name="blob", path="%INPUT_CONTAINER%/{name}", connection="AzureWebJobsStorage")
def process_blob(blob: func.InputStream, name: str):
    try:
        logger.info("Processing blob: %s, size: %d", name, blob.length if blob.length else -1)

        content = blob.read()
        result = _process_blob_content(content, name)

        container = _get_cosmos_container()
        item = {
            "id": name,
            "partitionKey": name,
            **result,
            "sourceContainer": os.environ.get("INPUT_CONTAINER", ""),
            "sourceBlob": name,
        }
        container.upsert_item(item)

        _send_event(
            event_type="mvp.blob.processed",
            subject=f"blobs/{name}",
            data={
                "blobName": name,
                "status": "processed",
                "metrics": {
                    "byteLength": result["byteLength"],
                    "lineCount": result["lineCount"],
                    "wordCount": result["wordCount"],
                },
                "processedAt": result["processedAt"],
            },
        )

        logger.info("Successfully processed blob: %s", name)

    except Exception as exc:
        logger.exception("Failed to process blob: %s", name)
        try:
            _send_event(
                event_type="mvp.blob.failed",
                subject=f"blobs/{name}",
                data={
                    "blobName": name,
                    "status": "failed",
                    "error": str(exc),
                    "processedAt": datetime.now(timezone.utc).isoformat(),
                },
            )
        except Exception:
            logger.exception("Failed to send failure notification for blob: %s", name)
        raise


